"""
MKT Context Commentary — Deuteronomy 5–7 (84 verses)
Run: python3 scripts/zc-context-deuteronomy-5-7.py
Key decisions:
- Ch 5 Decalogue: focus on the differences between Exod 20 and Deut 5
  (Sabbath motivation changes from creation to Egypt-memory; slight word
  changes throughout); also the Horeb assembly scene as historical context
- Ch 6 Shema: the ANE polytheistic context that makes 6:4 revolutionary;
  the mezuzah practice of v9 as ongoing liturgical tradition; the
  catechism of vv20-25 as the earliest recorded Q&A religious education
- Ch 7 holy people: the seven nations list and archaeological evidence;
  the cherem (ban) in comparative ANE context (Mesha Stele parallel);
  the covenantal blessing structure (vv12-16) as treaty-form sanction
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(layer, book):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    return json.loads(p.read_text()) if p.exists() else {}


def save_comm(layer, book, data):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=2))


def merge_comm(existing, new_data):
    # INTENT: Write only absent keys so re-running is safe after manual edits.
    # CHANGE? If deuteronomy.json schema changes, update merge_comm and DEUT dict below.
    # VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-context/deuteronomy.json')); print(d.get('5',{}).get('6','MISSING')[:80])"
    for ch, verses in new_data.items():
        existing.setdefault(ch, {})
        for v, text in verses.items():
            existing[ch].setdefault(v, text)


DEUT = {
    "5": {
        "1": "<p>Deuteronomy 5 opens the second major speech of Deuteronomy (5:1–28:68), the law-code proper. Moses summons all Israel to hear the statutes and ordinances that constitute the covenant law. The phrase \"all Israel\" (<em>kol Yisrael</em>) is characteristic of Deuteronomy's rhetorical strategy: this is a plenary assembly, not a gathering of representatives or elders only. The covenant is addressed to the whole people, which distinguishes it from ANE vassal-treaty practice where only the king and his court received the document. In Deuteronomy, every Israelite is a treaty-party with YHWH.</p>",
        "2": "<p>\"The LORD our God made a covenant with us at Horeb\" — the historical grounding: the law that follows is covenant-renewal, not new legislation. The covenant at Horeb/Sinai is the foundational legal event. Deuteronomy regularly refers to Sinai as \"Horeb\" — the name may reflect a northern tradition (used in Elijah's story, 1 Kgs 19:8) while Exodus/Numbers use \"Sinai\" (possibly a southern tradition). Both names refer to the same mountain; the variant usage is a linguistic marker of Deuteronomy's distinct literary tradition within the Pentateuch.</p>",
        "3": "<p>\"Not with our fathers did the LORD make this covenant, but with us, who are all of us here alive today\" — the contemporizing principle: the covenant is addressed to the present generation as direct parties, not as inheritors of a past agreement. This is a deliberate rhetorical move: Moses is speaking to the children of the Exodus generation, yet declares the Horeb covenant was made \"with us here today.\" The covenant is not historical in the sense of past and over — it is perpetually contemporaneous. Each generation stands before YHWH as if present at Sinai. This principle shapes all subsequent Jewish interpretation of Exodus and Deuteronomy: the Passover Haggadah institutionalizes it (\"In every generation, each person is obligated to see himself as if he personally left Egypt\").</p>",
        "4": "<p>\"The LORD spoke with you face to face at the mountain, out of the midst of the fire\" — the Horeb theophany recalled: YHWH spoke directly, not through an intermediary, to the whole assembly. This direct divine speech to an entire nation is presented as unique and unprecedented (Deut 4:33: \"Did any people ever hear the voice of a god speaking out of the midst of fire, as you have heard, and still live?\"). The claim of national-direct revelation is one of Deuteronomy's most distinctive theological arguments: the covenant rests on a publicly witnessed event, not private tradition.</p>",
        "5": "<p>Moses as mediator: \"while I stood between the LORD and you at that time, to declare to you the word of the LORD, for you were afraid because of the fire\" — the mediatorial role of Moses is here explained as arising from the people's fear of the divine fire. In Exodus 20:18-20 the people request Moses's mediation after hearing YHWH's voice. Deuteronomy presents this as the historical context for Moses's unique role. The mediator-pattern — YHWH speaks to Moses, Moses speaks to the people — is the structural model for all subsequent prophetic revelation in Israel.</p>",
        "6": "<p>\"I am the LORD your God, who brought you out of the land of Egypt, out of the house of slavery\" — the prologue to the Decalogue: the same self-identification formula appears in both recensions (Exod 20:2 and Deut 5:6). In Hittite suzerainty treaty form, this corresponds to the preamble section (identifying the great king) and the historical prologue (recounting the king's benefits to the vassal). YHWH identifies himself not as creator-God abstractly but as the specific God who performed the Exodus — the covenant is grounded in historical act, not metaphysical claim.</p>",
        "7": "<p>\"You shall have no other gods before me\" — the first commandment in its ANE context: the surrounding Canaanite world practiced monolatry (worship of one primary deity within a pantheon) rather than monotheism. The Ugaritic texts (discovered at Ras Shamra beginning 1929) show a pantheon dominated by El and Baal with dozens of associated deities. The Decalogue's first commandment does not deny the existence of other divine beings but prohibits their worship: \"before my face\" (<em>al panai</em>) means YHWH's presence tolerates no rival worship. The practical monotheism of Deuteronomy becomes explicit theoretical monotheism in Deutero-Isaiah (Isa 44:6: \"besides me there is no God\").</p>",
        "8": "<p>The prohibition of images (<em>pesel</em>, H6459): the second commandment prohibits carved images of anything in heaven, earth, or water — not just images of other gods but images of YHWH himself. The Egyptian religious world was saturated with divine images; the Canaanite cult used standing stones (<em>masseboth</em>) and Asherah poles. Israel's imageless worship was so distinctive that Greek and Roman observers commented on it (Josephus, Tacitus, Juvenal all note the absence of divine images in the Jerusalem temple). The aniconism of Israelite worship is one of its most archaeologically confirmed characteristics — the absence of divine figurines in Israelite contexts (though not universal) contrasts with the ubiquity of such items in Canaanite sites.</p>",
        "9": "<p>\"For I the LORD your God am a jealous God (<em>el qanna</em>), visiting the iniquity of the fathers on the children to the third and fourth generation of those who hate me\" — the jealousy (<em>qanna</em>, H7067) of YHWH reflects the covenant's exclusive-loyalty structure. Ancient treaties imposed exclusive loyalty obligations: the vassal could not have treaty relations with the suzerain's enemies. The generational consequence language reflects solidarity thinking: families share in consequences of the head's covenant loyalty or disloyalty. The Babylonian Talmud (Sanhedrin 27b-28a) wrestled with this in relation to Deuteronomy 24:16's individual-responsibility principle, concluding the generational consequence refers to those who continue in the parents' sin.</p>",
        "10": "<p>\"But showing steadfast love (<em>chesed</em>, H2617) to thousands of those who love me and keep my commandments\" — the asymmetry is deliberate and theologically significant: sin visits to three-four generations; <em>chesed</em> extends to thousands (of generations). The ratio is approximately 2500:4. The covenant's mercy far outweighs its judgment in scope and duration. <em>Chesed</em> (H2617) is the covenant-loyalty term: YHWH's loyal love to those who keep the covenant. This is the <em>chesed</em> that Ruth shows Naomi (Ruth 1:8; 3:10) and that defines YHWH's character (Exod 34:6-7: \"abounding in steadfast love and faithfulness\").</p>",
        "11": "<p>The third commandment: \"You shall not take the name of the LORD your God in vain\" — the Hebrew <em>lo tissa et-shem YHWH eloheicha lashav</em> (do not lift up the name of YHWH your God to emptiness/falsehood). The commandment primarily addresses false oaths — invoking YHWH's name as guarantor of a false statement. In the ancient world, oaths sworn in a deity's name carried enormous legal and religious weight; using that name for false oaths or frivolous purposes was a direct assault on YHWH's honor and the community's trust infrastructure. The secondary application to careless speech is also included in the command's scope.</p>",
        "12": "<p>The Sabbath commandment in Deuteronomy 5: \"Observe the Sabbath day, to keep it holy, as the LORD your God commanded you\" — the Deuteronomy version uses <em>shamor</em> (observe/keep) while Exodus 20:8 uses <em>zachor</em> (remember). The rabbinic tradition harmonized these by noting both were spoken simultaneously at Sinai (<em>zachor veshamor bedibur echad</em>). The substantive difference is the motivational ground: Exodus 20 grounds the Sabbath in creation (God rested on the seventh day); Deuteronomy 5 grounds it in the Exodus (\"Remember that you were a slave in Egypt,\" v15). The two grounds are complementary: creation-order (cosmic) and redemption-history (covenant).</p>",
        "13": "<p>\"Six days you shall labor and do all your work\" — the six-day workweek as the Sabbath's context: the Sabbath is meaningful because it interrupts regular labor. The six-day work cycle may be contrasted with Babylonian approaches to time — the Babylonian <em>shappatu</em> was an unlucky day associated with the full moon, not a weekly-recurring day of rest. The seven-day week with a recurring day of abstention from work is a distinctive Israelite institution that the ancient world eventually adopted through Jewish and Christian influence. Canaanite and Egyptian calendars did not have a seven-day week as a regular unit.</p>",
        "14": "<p>\"But the seventh day is a Sabbath to the LORD your God. On it you shall not do any work, you or your son or your daughter or your male servant or your female servant, or your ox or your donkey or any of your livestock, or the sojourner who is within your gates, that your male servant and your female servant may rest as well as you\" — the inclusion of servants and sojourners: the Sabbath is the most radically equalizing institution of the ancient world. Slaves, who had no legal personhood in most ANE contexts, receive one day per week of the same rest as their masters. The Deuteronomy version adds \"your ox and your donkey and any livestock\" — extending the rest to working animals. This ecological dimension of Sabbath is distinctive.</p>",
        "15": "<p>\"You shall remember that you were a slave in the land of Egypt, and the LORD your God brought you out from there with a mighty hand and an outstretched arm\" — the Exodus-memory grounds the Deuteronomic Sabbath. The person who was a slave knows what it means not to rest; the liberated person cannot impose on another what they themselves suffered. The Exodus functions throughout Deuteronomy as the ethical conscience: remember your vulnerability, and protect the vulnerable now within your care. This memory-ethic is Deuteronomy's distinctive contribution to moral theology.</p>",
        "16": "<p>\"Honor your father and your mother, as the LORD your God commanded you, that your days may be long, and that it may go well with you in the land that the LORD your God is giving you\" — the fifth commandment with the Deuteronomic additions: Exodus 20:12 has \"that your days may be long in the land\"; Deuteronomy 5:16 adds \"as the LORD commanded you\" (linking it to the covenant's specificity) and \"that it may go well with you\" (the Deuteronomic blessing formula). Parents are the primary conduit of covenant tradition (Deut 6:20-25): honoring parents is not merely filial piety but covenant faithfulness — the parents embody the covenant memory that the children must receive.</p>",
        "17": "<p>\"You shall not murder\" — the sixth commandment: <em>lo tirtsach</em> (H7523, murder/kill with intent). The Hebrew verb distinguishes intentional killing (<em>ratsach</em>) from accidental killing (<em>harag</em> or <em>hemit</em>) — only the former is prohibited by this commandment. The cities of refuge (Deut 19) are designed for the accidental killer who needs protection from blood vengeance. Capital punishment and warfare are authorized under other commandments: the sixth commandment establishes the sanctity of human life specifically against personal violence, not all taking of life. ANE law codes (Code of Hammurabi, Middle Assyrian Laws) also prohibited murder but linked it to compensation and social status — Deuteronomy does not permit monetary substitution for murder.</p>",
        "18": "<p>\"And you shall not commit adultery\" — the seventh commandment: <em>lo tinaaf</em> (H5003, commit adultery). Ancient Near Eastern law codes generally prohibited adultery but defined it differently: the Code of Hammurabi §129 defined adultery as a married woman's intercourse with another man (not a married man's intercourse with an unmarried woman). The Deuteronomic commandment is parallel: it addresses the married woman's exclusive sexual covenant with her husband. The covenant-structure of marriage (the woman's sexual loyalty as covenant-symbol) is the theological framework, not merely a property-rights concern.</p>",
        "19": "<p>\"And you shall not steal\" — the eighth commandment: <em>lo tignov</em> (H1589). Like the sixth commandment, the specific Hebrew verb matters: <em>ganav</em> primarily meant to steal by stealth or deception (as opposed to robbery by force, <em>gazal</em>, H1497). Talmudic tradition (Sanhedrin 86a) identified this as primarily a prohibition of man-stealing (kidnapping): the earlier commands prohibit murder and adultery (capital offenses against persons); this one prohibits kidnapping (the capital offense of Deut 24:7). The general property-theft application was understood as included by extension.</p>",
        "20": "<p>\"And you shall not bear false witness against your neighbor\" — the ninth commandment: <em>lo ta'aneh vera'cha ed shav</em> (do not answer your neighbor as a false witness). The legal context is explicit: this is court testimony, not general lying. False testimony in the gate/court system was a capital offense under the lex talionis of Deuteronomy 19:16-21. The commandment protects the judicial system's integrity — without reliable testimony, the entire covenant-justice structure collapses. The Proverbs tradition makes false witness one of the seven things YHWH hates (Prov 6:19).</p>",
        "21": "<p>\"And you shall not covet your neighbor's wife. And you shall not desire your neighbor's house, his field, or his male servant, or his female servant, his ox, or his donkey, or anything that is your neighbor's\" — the tenth commandment in Deuteronomy: the order reverses Exodus 20:17 (which lists \"house\" first, then \"wife\"). This may reflect different social settings: Exodus 20 addresses a more nomadic context (house = tent), while Deuteronomy 5 reflects settled-agricultural life (field added explicitly). The two verbs differ: <em>lo tachmod</em> (Exod 20) vs. <em>lo tachmod... velo titavveh</em> (Deut 5) — the second verse adds <em>hitavveh</em> (desire/crave), addressing the internal appetite that produces the external action. This is the only commandment addressing inner desire; Augustine and Luther both noted its significance for understanding the law's total claim on the inner life.</p>",
        "22": "<p>\"These words the LORD spoke to all your assembly at the mountain out of the midst of the fire, the cloud, and the thick darkness, with a loud voice; and he added no more\" — the sealing formula: YHWH spoke these Ten Words directly to the assembly and then stopped. The Decalogue is the only portion of Torah delivered directly to the whole assembly without Mosaic mediation. \"He added no more\" (<em>velo yasaf</em>) may indicate the Decalogue is complete in itself, a closed utterance. The tablets of stone then contain these words written by God's own finger (v22b: \"he wrote them on two tablets of stone and gave them to me\").</p>",
        "23": "<p>The people's response: \"And as soon as you heard the voice out of the midst of the darkness, while the mountain was burning with fire, you came near to me, all the heads of your tribes, and your elders\" — the tribal-elder representative structure: in the moment of crisis, the formal leadership structure is invoked. The <em>rashei shivteichem</em> (heads of your tribes) and <em>zeqenichem</em> (elders) come forward as the community's official representatives to communicate the people's request for Mosaic mediation. This delegation moment formalizes Moses's mediatorial role.</p>",
        "24": "<p>\"Behold, the LORD our God has shown us his glory and greatness, and we have heard his voice out of the midst of the fire. This day we have seen God speak with man, and man still live\" — the theological observation: divine-human dialogue without death was considered impossible by the ancient world generally. Egyptian texts describe the terrifying overwhelming nature of divine presence; the OT itself repeatedly notes that seeing YHWH directly brings death (Exod 33:20; Judg 13:22; Isa 6:5). The fact that Israel survived hearing YHWH's voice at Sinai is recorded as exceptional and evidence of YHWH's gracious intention toward them.</p>",
        "25": "<p>\"Now therefore why should we die? For this great fire will consume us. If we hear the voice of the LORD our God any more, we shall die\" — the people's theological analysis of their vulnerability: continued direct divine speech would be lethal. The argument is not fear-driven cowardice but accurate theological assessment: sustained exposure to the full weight of YHWH's presence exceeds what embodied humans can sustain. The request for Mosaic mediation is theologically sound — it is the covenant community's recognition of its creaturely limitation before the Creator's holiness.</p>",
        "26": "<p>\"For who is there of all flesh that has heard the voice of the living God speaking out of the midst of fire as we have, and has still lived?\" — the rhetorical question implies an unprecedented event. The phrase \"living God\" (<em>elohim chayyim</em>) distinguishes YHWH from the inert idols of the nations (Jer 10:10; 1 Thess 1:9): this is the God who is alive, active, speaking — and whose speech is therefore of a different order from human speech. The expression becomes a standard NT formula for YHWH's identity (Matt 16:16; Acts 14:15; Heb 10:31).</p>",
        "27": "<p>\"Go near and hear all that the LORD our God will say, and speak to us all that the LORD our God will speak to you, and we will hear and do it\" — the covenantal acceptance of the mediatorial structure: the people commit to hearing YHWH's word through Moses and obeying it. The double formula <em>nishma veasinu</em> (we will hear and do) is the covenantal response formula, matching the Exodus 24:7 formula at the original covenant ceremony. The people's consent to the mediatorial arrangement is itself a covenantal act.</p>",
        "28": "<p>\"And the LORD heard your words, when you spoke to me. And the LORD said to me, 'I have heard the words of this people, which they have spoken to you. They are right in all that they have spoken'\" — YHWH approves the people's assessment of their own situation and their request for mediation. The divine approval of the request prevents any implication that Mosaic mediation represents a failure of faith or access. YHWH himself validates the arrangement: the covenant people's recognition of their need for mediation is not timidity but theological accuracy.</p>",
        "29": "<p>\"Oh that they had such a heart as this always, to fear me and to keep all my commandments, that it might go well with them and with their descendants forever!\" — the divine wish: YHWH expresses desire for the continued faithfulness of the heart-posture the people currently display at Horeb. The condition at Horeb — fear, willingness to hear, commitment to do — is the ideal covenant relationship. The \"Oh that...\" (<em>mi yitten</em>) is the wish-particle expressing that this ideal will not in fact be maintained. Jeremiah 31:33 and Ezekiel 36:26-27 are the prophetic answers to this divine wish: YHWH himself will change the heart that cannot maintain the Horeb posture.</p>",
        "30": "<p>\"Go and say to them, \"Return to your tents.\"\" — the dismissal of the assembly back to ordinary life: the theophany is over, the terms of the covenant declared, the mediatorial arrangement established. \"Return to your tents\" is the standard dismissal formula for public assembly (cf. 1 Kgs 12:16: \"To your tents, O Israel!\"). The covenant people return to their normal domestic life carrying the covenant's claims as the structure of that ordinary life.</p>",
        "31": "<p>\"But you, stand here by me, and I will tell you the whole commandment and the statutes and the rules that you shall teach them\" — Moses's distinctive calling: to stand before YHWH and receive the full Torah that he will then teach the community. The verb <em>teach</em> (<em>limmed</em>, H3925) is Deuteronomy's characteristic educational verb — it appears more in Deuteronomy than all other books of the OT combined. Moses is not just a lawgiver but a teacher; Deuteronomy is a teaching document, not merely a legal code.</p>",
        "32": "<p>\"You shall be careful therefore to do as the LORD your God has commanded you. You shall not turn aside to the right hand or to the left\" — the covenant faithfulness formula: the right-left non-turning image appears throughout Deuteronomy and Joshua (Deut 17:11,20; 28:14; Josh 1:7; 23:6). The image of staying on the path without deviation is both physical (no wandering) and moral (no disobedience). In suzerainty treaties, precise compliance with the stipulations was required — partial obedience was still a treaty violation.</p>",
        "33": "<p>\"You shall walk in all the way that the LORD your God has commanded you, that you may live, and that it may go well with you, and that you may live long in the land that you shall possess\" — the covenant life-formula: walk (<em>halach</em>) + all the way + that you may live (<em>lemaan tichyun</em>) + that it may go well (<em>vetov lachem</em>) + that you may live long (<em>vehaarachtem yamim</em>). This three-part blessing formula is Deuteronomy's signature motivational structure, repeated throughout the book. The walking/way (<em>derech</em>) metaphor for covenant life becomes the primary metaphor of the wisdom tradition (Proverbs 1-9) and then of the early Christian movement (<em>hodos</em>, Acts 9:2; 18:25-26; 19:9,23).</p>"
    },
    "6": {
        "1": "<p>\"Now this is the commandment — the statutes and the rules — that the LORD your God commanded me to teach you, that you may do them in the land to which you are going over, to possess it\" — the transition from the Decalogue (ch 5) to the law code proper: ch 6 introduces the great interpretive principle (the Shema, vv4-5) that governs all the laws that follow. The land-destination framing is deliberate: this is law for the land, not for the wilderness. The stipulations are oriented toward sedentary life — farming, urban living, regular worship at a central sanctuary.</p>",
        "2": "<p>\"That you may fear the LORD your God, you and your son and your son's son, by keeping all his statutes and his commandments, which I command you, all the days of your life, and that your days may be long\" — the three-generation formulation: you, your son, your son's son. Covenant faithfulness is inherently multigenerational. The law is not an individual matter but a family-and-community project requiring transmission across generations. The \"all your days\" temporal scope means the covenant claims the entirety of life, not just formal religious occasions.</p>",
        "3": "<p>\"Hear therefore, O Israel, and be careful to do them, that it may go well with you, and that you may multiply greatly, as the LORD, the God of your fathers, has promised you, in a land flowing with milk and honey\" — the promised-land description: \"a land flowing with milk and honey\" (<em>eretz zavat chalav udvash</em>) appears 20 times in the Pentateuch and is the signature description of Canaan's agricultural abundance. Archaeologically, the Syro-Palestinian region supported both pastoral livestock (milk) and beekeeping/flowering plants (honey). The phrase is formulaic but grounded in the actual agricultural potential of the Levantine land compared to the desert Israel was leaving.</p>",
        "4": "<p>\"Hear, O Israel: The LORD our God, the LORD is one\" — the Shema (from <em>shema</em>, hear/listen): this six-word declaration (in Hebrew: <em>shema Yisrael YHWH eloheinu YHWH echad</em>) became the central confession of Judaism, recited twice daily. Its reception in the ANE world: the Canaanite city-states each had their own ba'al (lord/master), typically identified with Baal Hadad or El. The Philistines had Dagon. The Moabites had Chemosh. The Ammonites had Molech. The Shema asserts that the God of Israel is not one regional deity among many but the only LORD — a revolutionary claim in a world of territorial polytheism. The Ugaritic texts show the complexity of Canaanite divine bureaucracy; the Shema sweeps it away with six words.</p>",
        "5": "<p>\"You shall love the LORD your God with all your heart and with all your soul and with all your might\" — the <em>ahavah</em> (love) command: love of the deity was not a common feature of ANE religious expression, which focused on propitiation, service, and fear. Deuteronomy's command to love YHWH is distinctive. The three dimensions — heart (<em>levav</em>), soul (<em>nefesh</em>), and might (<em>meod</em>) — comprehensively cover the rational-volitional center, the animate life-self, and the material resources. Mark 12:30 adds a fourth dimension (\"mind\") by distinguishing <em>levav</em> and <em>dianoia</em> in the Greek. The Shema-love command is the summary of the entire Torah (as Jesus teaches in Matt 22:37-40).</p>",
        "6": "<p>\"And these words that I command you today shall be on your heart\" — the internalization imperative: the law is not merely an external code but something to be carried inside the person. The <em>lev</em> (heart) is the center of decision-making and intention in Hebrew anthropology. The law on the heart is the precursor to Jeremiah 31:33's new covenant promise — but Deuteronomy 6:6 commands what Jeremiah 31:33 promises as a divine gift. The gap between the command (Deut 6:6) and the gift (Jer 31:33) is the gap between old covenant demand and new covenant provision.</p>",
        "7": "<p>\"You shall teach them diligently to your children, and shall talk of them when you sit in your house, and when you walk by the way, and when you lie down, and when you rise\" — the total-life-embedding of Torah: four times of day (sitting, walking, lying down, rising up) cover the full round of daily life. Teaching children is not confined to formal instruction sessions but embedded in every daily activity. The home (<em>beitecha</em>) and the road (<em>vederech</em>) are both Torah-teaching spaces. The pedagogy is conversational and situational, not only formal-instructional. The Jewish practice of discussing Torah at the dinner table, on the Sabbath walk, and at bedtime derives directly from this verse.</p>",
        "8": "<p>\"You shall bind them as a sign on your hand, and they shall be as frontlets between your eyes\" — the phylactery command: <em>totafot</em> (H2903, frontlets/phylacteries) are the objects worn on the forehead; tefillin in later Jewish practice are leather boxes containing Torah passages (Exod 13:1-16; Deut 6:4-9; 11:13-21) worn on the arm and forehead during morning prayer. The command may be understood literally (as Jewish practice has), metaphorically (law always before your eyes/guiding your actions), or both. Matthew 23:5 criticizes the scribes and Pharisees for widening their phylactery boxes for show — confirming the practice was widespread by the first century CE.</p>",
        "9": "<p>\"You shall write them on the doorposts of your house and on your gates\" — the mezuzah tradition: a <em>mezuzah</em> (doorpost) scroll containing Deuteronomy 6:4-9 and 11:13-21 was affixed to doorposts in Jewish homes. The command's literalizing produced one of Judaism's most visible and durable practices — the mezuzah has been an identifying mark of Jewish homes for millennia. Archaeologically, inscribed doorpost plaques have been found at ancient sites. The mezuzah practice embeds the covenant's claim into the physical structure of the home: YHWH's words mark the threshold, turning the domestic space into covenanted space.</p>",
        "10": "<p>\"And when the LORD your God brings you into the land that he swore to your fathers, to Abraham, to Isaac, and to Jacob, to give you — with great and good cities that you did not build\" — the danger of prosperity: vv10-12 address the theological risk of inheriting developed civilization. The cities, houses, cisterns, vineyards, and olive trees were built and planted by others. The danger is that prosperity without struggle produces forgetting. This is one of the earliest recorded analyses of the spiritual danger of inherited wealth and civilizational comfort.</p>",
        "11": "<p>Houses filled with all good things that you did not fill, and cisterns that you did not dig, and vineyards and olive trees that you did not plant — the comprehensive list of inherited goods. Cisterns cut in bedrock were major infrastructure investments in the ancient Levant, where water was scarce. Vineyards and olive groves required decades of cultivation before becoming productive. Israel is about to inherit the infrastructure and agriculture of civilizations they did not build — a profound economic gift that carries proportional spiritual risk.</p>",
        "12": "<p>\"Then take care lest you forget the LORD, who brought you out of the land of Egypt, out of the house of slavery\" — the forget-warning: <em>hishamer lecha pen tishkach</em> (take care lest you forget). Forgetting YHWH is the root of all subsequent covenant failure in Deuteronomy's framework. The entire book of Judges demonstrates this pattern: Israel settles, prospers, forgets YHWH, worships Baal, suffers, cries out, YHWH raises a judge, delivers, and the cycle repeats. The forget-warning at the threshold of the land is the narrative setup for everything that follows in the Deuteronomistic History.</p>",
        "13": "<p>\"It is the LORD your God you shall fear. Him you shall serve and by his name you shall swear\" — the exclusive-service command: YHWH alone receives fear (<em>yira</em>), service (<em>avad</em>), and oath-backing (<em>shevuah</em>). Jesus quotes 6:13 to Satan in the wilderness temptation (Matt 4:10; Luke 4:8): \"You shall worship the Lord your God, and him only shall you serve\" — the Shema's exclusive-service command becomes the hermeneutical lens for Jesus's rejection of demonic homage. Satan's offer of \"all the kingdoms of the world\" is precisely the kind of offer the Canaanite land-gift might become: prosperity in exchange for serving a different lord.</p>",
        "14": "<p>\"You shall not go after other gods, the gods of the peoples who are around you\" — the specific prohibition against the surrounding nations' gods: Baal (Canaanite storm god), Asherah (Canaanite goddess of fertility), Dagon (Philistine grain god), Chemosh (Moabite), Molech (Ammonite) are the specific deities Israel is warned against throughout the subsequent history. The Deuteronomistic History (Joshua through Kings) is structured as an account of how well Israel kept this command — the answer being \"not well at all.\" The failure to maintain exclusive YHWH-worship is the recurring explanatory key for every national disaster.</p>",
        "15": "<p>\"For the LORD your God in your midst is a jealous God (<em>el qanna</em>), lest the anger of the LORD your God be kindled against you, and he destroy you from the face of the earth\" — the jealousy-warning amplifies the second commandment's jealousy language (5:9). The presence of YHWH in the community's midst is the source of both protection and danger: the same divine presence that delivers also punishes covenant violation. The spatial metaphor \"in your midst\" (<em>beqirbecha</em>) anticipates the tabernacle and temple's function as the place where YHWH's presence is concentrated within the community.</p>",
        "16": "<p>\"You shall not put the LORD your God to the test, as you tested him at Massah\" — the Massah reference: at Massah (\"testing,\" Exod 17:1-7) Israel demanded water and questioned whether YHWH was among them at all. The testing of YHWH is the application of empirical skepticism to covenant faith: treating YHWH's faithfulness as a hypothesis to be verified rather than a covenant reality to be trusted. Jesus quotes this verse to Satan (Matt 4:7; Luke 4:12) in response to the temptation to jump from the temple pinnacle and summon angelic rescue — another form of demanding that God prove himself.</p>",
        "17": "<p>\"You shall diligently keep the commandments of the LORD your God, and his testimonies and his statutes, which he has commanded you\" — the threefold covenant-vocabulary: <em>mitzvot</em> (commandments), <em>edut</em> (testimonies/witness), <em>chuqqim</em> (statutes). The three terms appear together throughout Deuteronomy and the Psalms (Ps 119 uses all three and more). The distinctions are sometimes drawn: <em>mitzvot</em> as general commands, <em>chuqqim</em> as statutes without stated reasons (like the dietary laws), <em>mishpatim</em> as case-law. The threefold repetition emphasizes comprehensive covenant coverage: every category of divine instruction is to be kept.</p>",
        "18": "<p>\"And you shall do what is right and good in the sight of the LORD, that it may go well with you, and that you may go in and take possession of the good land that the LORD swore to give to your fathers\" — the summary principle: \"right and good in the sight of the LORD\" (<em>hayashar vehatov be'einei YHWH</em>) is an open-ended standard beyond specific law. Even where no specific commandment applies, the covenant person asks what is right and good before YHWH. This principle prevents the legalism of \"anything not explicitly prohibited is permitted\" — the covenant shapes character, not just compliance.</p>",
        "19": "<p>\"By thrusting out all your enemies from before you, as the LORD has promised\" — the land-possession is presented as YHWH's pushing-out of enemies (<em>lehadof</em>): Israel's military activity is secondary to YHWH's action. The same verb (<em>dafah</em>) is used in Exodus for YHWH's action against Egypt. Israel's conquest of Canaan is framed throughout Deuteronomy as YHWH's action, not Israel's military prowess (Deut 9:4-6: \"not because of your righteousness\").</p>",
        "20": "<p>\"When your son asks you in time to come, 'What is the meaning of the testimonies and the statutes and the rules that the LORD our God has commanded you?'\" — the catechetical question-and-answer: the son's question and the father's response (vv21-25) is the earliest recorded formal religious education format in the Bible. The Passover Haggadah formalizes this into four sons with four questions, reflecting this Deuteronomic pattern. The question-and-answer method ensures the covenant story is transmitted relationally, not merely textually — the next generation must ask, and the current generation must be ready to answer.</p>",
        "21": "<p>\"Then you shall say to your son, 'We were Pharaoh's slaves in Egypt. And the LORD brought us out of Egypt with a mighty hand'\" — the catechetical answer begins with the confession of slavery: the covenant history starts with the lowest point (slavery), not with the patriarchal glory. The starting point of humility and need is theologically significant: the covenant identity is not built on ethnic superiority but on received rescue. The Passover confession has this same structure: we were slaves, YHWH brought us out.</p>",
        "22": "<p>\"And the LORD showed signs and wonders, great and grievous, against Egypt and against Pharaoh and all his household, before our eyes\" — \"before our eyes\" (<em>le'eineinu</em>): the eyewitness claim is part of the catechetical answer. The father tells his son: we saw this. The participatory identity (\"we were slaves,\" \"we saw\") creates covenantal solidarity across generations — the son inhabits the Exodus story as his own, not as a distant ancestor's story. This is the Deuteronomic contemporization principle in its catechetical form.</p>",
        "23": "<p>\"And he brought us out from there, that he might bring us in and give us the land that he swore to give to our fathers\" — the double movement of redemption: brought out (from Egypt) → brought in (to Canaan). The two movements define the Exodus as purposive: liberation was not the end goal but the means to the land-gift. This double-movement (exodus → entry) becomes the NT's hermeneutical framework: Christ brought us out (from sin/death) to bring us in (to the kingdom/rest). Hebrews 3-4 uses this framework explicitly.</p>",
        "24": "<p>\"And the LORD commanded us to do all these statutes, to fear the LORD our God, for our good always, that he might preserve us alive, as we are this day\" — the covenant's self-interest argument: obedience is \"for our good\" (<em>letovatenu</em>). The covenant is not primarily YHWH's benefit (he gains nothing from Israel's obedience) but Israel's — the statutes are designed as life-giving instructions, not arbitrary impositions. Paul uses similar logic in Romans 7:12 (\"the law is holy, and the commandment is holy and righteous and good\") — the law's goodness is not undermined by its inability to produce righteousness; it remains good even when humans are unable to keep it.</p>",
        "25": "<p>\"And it will be righteousness for us, if we are careful to do all this commandment before the LORD our God, as he has commanded us\" — the righteousness-by-Torah promise: covenant faithfulness produces righteousness (<em>tzedaqah</em>). This is the Torah's own promise — obedience to YHWH's commands constitutes the righteous life. Paul's argument in Romans 3:21-4:25 does not deny that Torah-righteousness was genuine righteousness for those who achieved it (Zacharias and Elizabeth in Luke 1:6 are described as \"righteous before God, walking blamelessly in all the commandments\") — his argument is that no one achieves it (Rom 3:10-18) and that a righteousness by faith was always available (Abraham's faith counted as righteousness, Gen 15:6, before circumcision).</p>"
    },
    "7": {
        "1": "<p>\"When the LORD your God brings you into the land that you are entering to take possession of it, and clears away many nations before you, the Hittites, the Girgashites, the Amorites, the Canaanites, the Perizzites, the Hivites, and the Jebusites, seven nations more numerous and mightier than you\" — the seven nations: this list appears in various configurations throughout the OT (Exod 3:8,17; 23:23; 33:2; Deut 20:17; Josh 3:10; 9:1; 12:8; 24:11). The number seven may represent completeness (all Canaanite peoples) rather than a precise historical roster. Archaeological identification of these groups is partial: Hittites in Canaan are likely Anatolian migrants or a Canaanite group using the name; Jebusites held Jerusalem (2 Sam 5:6-9); Amorites are attested in Mesopotamian sources as Semitic peoples of the Syrian-Palestinian region. The Girgashites and Perizzites are not attested outside the OT.</p>",
        "2": "<p>\"And when the LORD your God gives them over to you, and you defeat them, then you must devote them to complete destruction (<em>herem</em>). You shall make no covenant with them and show no mercy to them\" — the <em>herem</em> (devoted destruction / ban) in comparative ANE context: the Mesha Stele (ca. 835 BCE, Moab) is the closest ANE parallel, where King Mesha describes devoting the Israelite city of Nebo to Chemosh by killing all its inhabitants. The <em>cherem</em> ideology appears in several ANE conquest inscriptions: defeating enemies was dedicated to one's god by total destruction. In Israel, the <em>cherem</em> was YHWH's claim on conquered territory, preventing commercial exploitation of the victory and preventing cultural contamination through treaty-alliance with the defeated nations.</p>",
        "3": "<p>\"You shall not intermarry with them, giving your daughters to their sons or taking their daughters for your sons\" — the intermarriage prohibition: the ground (v4) is specifically religious, not ethnic. The concern is that intermarriage leads to adopting the spouse's deities. Solomon's intermarriages (1 Kgs 11:1-8) are the paradigmatic fulfillment of this warning: his foreign wives \"turned his heart after other gods.\" The Book of Ruth, by contrast, shows a Moabite woman absorbed into Israel through covenant loyalty rather than a Moabite man taking an Israelite woman into his religious orbit. The prohibition is directional: the danger is the Canaanite religious influence entering Israel, not the other way around.</p>",
        "4": "<p>\"For they would turn away your sons from following me, to serve other gods. Then the anger of the LORD would be kindled against you, and he would destroy you quickly\" — the stated rationale for the intermarriage prohibition: apostasy risk. The religious-contamination logic is consistent throughout the OT (and is invoked by Ezra-Nehemiah in the post-exilic period, Ezra 9-10). The historical validation: every major apostasy episode in Israel's history (golden calf, Baal-Peor, Baal of Tyre under Ahab, etc.) has an intermarriage or foreign-deity-adoption element.</p>",
        "5": "<p>\"But thus shall you deal with them: you shall break down their altars and dash in pieces their pillars and chop down their Asherim and burn their carved images with fire\" — the four destruction targets: (1) altars (<em>mizbeachot</em>), (2) pillars (<em>massevot</em>, standing stones), (3) Asherim (wooden poles representing the goddess Asherah), (4) carved images (<em>pesilim</em>). Archaeological excavations of Canaanite cult sites (like Megiddo, Hazor, and Lachish) have found all four types of cultic objects. The Bronze Age Canaanite cult was richly physical: outdoor high places, incised stone pillars, wooden goddess symbols, and divine figurines. Deuteronomy 7:5 is a systematic checklist for dismantling this entire material religion.</p>",
        "6": "<p>\"For you are a people holy to the LORD your God (<em>am qadosh lYHWH</em>). The LORD your God has chosen you to be a people for his treasured possession (<em>am segulah</em>), out of all the peoples who are on the face of the earth\" — the election theology: <em>am qadosh</em> (holy people) and <em>am segulah</em> (treasured possession/peculiar treasure). <em>Segulah</em> (H5459) appears in Ugaritic and Akkadian contexts as a king's personal property treasure, something distinct from the general treasury — a private collection of special value. Israel as YHWH's <em>segulah</em> is the covenant community as the divine king's personal treasure. 1 Peter 2:9 applies this to the church: \"a chosen race, a royal priesthood, a holy nation, a people for his own possession.\"</p>",
        "7": "<p>\"It was not because you were more in number than any other people that the LORD set his love on you and chose you, for you were the fewest of all peoples\" — the anti-merit election: YHWH's election of Israel is explicitly not based on numerical greatness (<em>rav</em>). The ground of election is entirely from YHWH's side (v8: \"because the LORD loves you and is keeping the oath that he swore to your fathers\"). This is the OT's clearest statement of unconditional election: Israel did not earn the relationship, and its continuance is not secured by Israel's performance but by YHWH's faithfulness to the oath he swore to Abraham. Paul in Romans 9:10-16 draws the same conclusion from the election of Jacob over Esau before birth.</p>",
        "8": "<p>\"But it is because the LORD loves you and is keeping the oath that he swore to your fathers, that the LORD has brought you out with a mighty hand and redeemed you from the house of slavery, from the hand of Pharaoh king of Egypt\" — the twin grounds of election: YHWH's love (<em>ahavah</em>) and his oath (<em>shevuah</em>) to the patriarchs. The love is not explained further — it is bedrock: YHWH loves because he loves (v8 does not explain why he loves). The oath introduces covenant continuity: the Exodus is the keeping of the promise to Abraham, Isaac, and Jacob (Gen 12:1-3; 15:18; 22:15-18). Election is both gracious (love without merit) and historical (oath to the fathers).</p>",
        "9": "<p>\"Know therefore that the LORD your God is God, the faithful God (<em>el hane'eman</em>) who keeps covenant and steadfast love with those who love him and keep his commandments, to a thousand generations\" — <em>el hane'eman</em> (the faithful/reliable God): the word <em>ne'eman</em> (H539) is from the same root as <em>amen</em> and <em>emet</em> (truth). YHWH's covenant faithfulness extends to a thousand generations of those who love him. The covenantal statistics: curse reaches three-four generations (5:9); faithful love extends to a thousand. The ratio (ca. 250:1) makes the covenantal economy overwhelmingly weighted toward mercy. This is the character of the God who keeps covenant — his faithfulness exceeds his judgment by orders of magnitude.</p>",
        "10": "<p>\"And repays to their face those who hate him, by destroying them. He will not be slack with one who hates him. He will repay him to his face\" — the reciprocal covenant consequence for those who hate YHWH: the covenant's unconditional election does not guarantee unconditional protection. Election is the framework of relationship; faithfulness or unfaithfulness within that relationship determines blessing or curse. The phrase \"to his face\" (<em>el panav</em>) emphasizes personal accountability — no proxy judgment, no delayed accounting, but direct personal consequence.</p>",
        "11": "<p>\"You shall therefore be careful to do the commandment and the statutes and the rules that I command you today\" — the conclusion of the election theology section: the response to YHWH's faithful election is careful covenant keeping. The word <em>shamor</em> (be careful/keep) closes the theological arc that began with the Shema (6:4) and election (7:6-10): knowing the character of YHWH and the ground of election produces not presumptuous security but motivated obedience.</p>",
        "12": "<p>\"And because you listen to these rules and keep and do them, the LORD your God will keep with you the covenant and the steadfast love that he swore to your fathers\" — the treaty-blessing condition: covenant faithfulness from Israel triggers YHWH's covenant faithfulness to them. The structure is not a merit-system (Israel does not earn YHWH's love by obedience) but a covenant-system (Israel's faithfulness is the covenant's expected mode of operation). The blessings follow as covenant consequence, not moral reward. Deuteronomy 28's blessing-curse list (the sanction section of the treaty form) is the extended development of this principle.</p>",
        "13": "<p>\"He will love you, bless you, and multiply you. He will also bless the fruit of your womb and the fruit of your ground, your grain and your wine and your oil, the increase of your herds and the young of your flock, in the land that he swore to your fathers to give you\" — the comprehensive material blessing: the covenant blessing covers the full agricultural economy (grain, wine, oil) and pastoral economy (cattle, sheep). In the ANE world, these material blessings were attributed to Baal (storm god bringing rain for grain), Asherah (fertility), and El (cattle). The Deuteronomic covenant claims all these blessings as YHWH's gift — the covenant monotheism means YHWH, not Baal, controls the rain; YHWH, not Asherah, controls fertility. The Baal-cycle mythology that explained rain and agriculture is replaced by covenant theology.</p>",
        "14": "<p>\"You shall be blessed above all peoples. There shall not be male or female barren among you or among your livestock\" — the infertility-reversal blessing: barrenness was the most feared personal disaster in the ancient world, where children were the primary economic and social security system. The blessing of full fertility for humans and livestock covers both the personal (family continuity) and economic (herd maintenance) dimensions. Rachel's prayer (Gen 30:1: \"Give me children or I shall die\") captures the cultural weight that makes this covenant blessing so powerful.</p>",
        "15": "<p>\"And the LORD will take away from you all sickness, and none of the evil diseases of Egypt that you knew will he put on you, but he will lay them on all who hate you\" — the health-covenant: the Egyptian diseases may refer to the plagues (in reversal: no more plagues for Israel) or to the endemic diseases of the Nile Delta (schistosomiasis, malaria, dysentery). In the ANE world, health and sickness were attributed to divine favor and disfavor. YHWH's covenant with Israel includes health protection — a stark contrast to the disease-producing deities of Egypt (who were placated through elaborate ritual). The complete health-blessing is realized eschatologically in the new creation (Rev 21:4: \"no more death or mourning or crying or pain\").</p>",
        "16": "<p>\"And you shall consume all the peoples that the LORD your God will give over to you. Your eye shall not pity them, neither shall you serve their gods, for that would be a snare to you\" — the no-pity command: <em>lo tachos einecha</em> (your eye shall not pity). The covenant's military program is maintained by suppressing the natural human response of mercy toward conquered peoples. The snare-warning (<em>moquesh</em>) explains the no-pity command: any preserved Canaanite population and its religious infrastructure will be a trap for Israel's covenant faithfulness. The historical validation: wherever Canaanite populations were preserved (the Gibeonites, Josh 9; the Canaanites of Judges 1-2), apostasy followed.</p>",
        "17": "<p>\"If you say in your heart, 'These nations are greater than I. How can I dispossess them?'\" — the heart-question as the key battlefield: the military challenge of dispossessing numerically/militarily superior nations will produce the same heart-question the spy-generation asked in Numbers 13. Deuteronomy anticipates the temptation and addresses it before it arises in the land. The catechetical format (\"if you say in your heart... then remember\") is educational pre-emptive strike: address the doubt before the situation produces it.</p>",
        "18": "<p>\"You shall not be afraid of them but you shall remember what the LORD your God did to Pharaoh and to all Egypt\" — the Pharaoh-paradigm as anti-fear medicine: what YHWH did to the greatest imperial power of the ancient world (Egypt under Ramesses II or Thutmose III) is the basis for confidence against the Canaanite city-states. The Amarna Letters (ca. 1350 BCE) show the Canaanite city-states writing to the Egyptian pharaoh for military help against various threats — Egypt was the overlord of Canaan during this period. Israel is told not to fear powers that were themselves client-states of the power YHWH had just defeated.</p>",
        "19": "<p>\"The great trials that your eyes saw, the signs, the wonders, the mighty hand, and the outstretched arm, by which the LORD your God brought you out. So will the LORD your God do to all the peoples of whom you are afraid\" — the Exodus-as-template: what YHWH did in Egypt (signs, wonders, mighty hand, outstretched arm) he will replicate against the Canaanite nations. The stereotyped Exodus description (\"mighty hand and outstretched arm\") appears 20+ times in Deuteronomy. By making the Exodus the template for all future divine action, Deuteronomy establishes the Exodus as the paradigm event of covenant history — the lens through which all subsequent YHWH-action is to be understood.</p>",
        "20": "<p>\"Moreover, the LORD your God will send hornets among them, until those who are left and hide themselves from you are destroyed\" — the hornet weapon: <em>tzir'ah</em> (H6880, hornet/wasp) is mentioned in Exod 23:28 and Josh 24:12 as a divine weapon. Whether literal (plague of hornets) or metaphorical (panic, or perhaps the Egyptian hornet as the symbol of Pharaoh — Pharaoh was depicted with the hornet in Egyptian royal iconography) is debated. Either way, it represents a hidden divine weapon beyond Israel's military resources that pursues those who hide from Israel's army.</p>",
        "21": "<p>\"You shall not be in dread of them, for the LORD your God is in your midst, a great and awesome God\" — the divine-presence-as-courage: <em>YHWH eloheicha beqirbecha el gadol venora</em>. The same divine presence that makes the camp holy (23:14) makes Israel's position in battle unassailable in principle. The Ark of the Covenant (the physical symbol of YHWH's presence) traveled with the Israelite army precisely because the army's power was derivative of divine presence. Uzzah's death (2 Sam 6:6-7) and the Philistines' capture of the Ark (1 Sam 4-5) are narratives that explore the dangerous power of YHWH's presence.</p>",
        "22": "<p>\"The LORD your God will clear away these nations before you little by little. You may not make an end of them at once, lest the wild beasts grow too numerous for you\" — the gradual-possession strategy: <em>meat meat</em> (little by little). The practical reason given (wild animal population control) reflects the agricultural reality of the ancient Levant: depopulated land quickly becomes wilderness that large predators (lions, bears) inhabit. The gradual-displacement strategy also reflects YHWH's mercy toward the Canaanites — giving more time before the judgment falls (cf. Gen 15:16: \"the iniquity of the Amorites is not yet complete\").</p>",
        "23": "<p>\"But the LORD your God will give them over to you and throw them into great confusion, until they are destroyed\" — the divine-panic weapon: <em>hamam</em> (H2000, to confuse/throw into panic). YHWH's military strategy includes supernatural terror sent into the enemy's hearts (cf. Josh 2:9: Rahab reports that Israel's God sent terror before them; Josh 10:10: YHWH threw the enemies into panic at Gibeon). The concept of the panic-inducing divine warrior appears throughout ANE military texts but is given its distinctive covenant-theological shape in Deuteronomy and Joshua.</p>",
        "24": "<p>\"And he will give their kings into your hand, and you shall make their name perish from under heaven. No one shall be able to stand against you until you have destroyed them\" — the royal-destruction command: capturing and destroying the enemy king is the decisive act of ancient conquest. The Canaanite city-state structure was king-centered (as the Amarna Letters show): destroy the king, and the city's political structure collapses. The book of Joshua records the defeat of thirty-one kings (Josh 12:24), fulfilling this promise systematically.</p>",
        "25": "<p>\"The carved images of their gods you shall burn with fire. You shall not covet the silver or the gold that is on them or take it for yourselves, lest you be ensnared by it, for it is an abomination to the LORD your God\" — the idol-wealth prohibition: the silver and gold decorating the idols are <em>toevah</em> (abomination) because they are integral to the cultic system. Achan's sin (Josh 7) involves taking devoted items — the <em>cherem</em> is extended to divine-image wealth. The temptation of the image's material value (silver and gold) is precisely the snare Deuteronomy 7:25 warns against: the economic logic of \"I'll take the silver but not worship the idol\" doesn't work because the material is inseparable from its cultic meaning.</p>",
        "26": "<p>\"And you shall not bring an abominable thing into your house and become devoted to destruction like it. You shall utterly detest and abhor it, for it is devoted to destruction\" — the contagion principle: cultic objects bring their dedicated status (<em>cherem</em>) into any space they enter. The idol in the house makes the house a <em>cherem</em>-object. The double-abhor formula (<em>shaqatz teshaqetzenu vetaev teta'avenu</em>) — the intensified construction of total rejection — is the strongest possible language for complete avoidance. The household as covenant space (the mezuzah marks the threshold; the doorpost-written law marks the walls) cannot simultaneously harbor idols. YHWH's presence and the idol's presence are incompatible.</p>"
    }
}


def main():
    existing = load_comm("mkt-context", "deuteronomy")
    before = sum(len(v) for v in existing.values())
    merge_comm(existing, DEUT)
    after = sum(len(v) for v in existing.values())
    save_comm("mkt-context", "deuteronomy", existing)
    print(f"{len(existing)} chapters, {after} verse entries total (+{after - before} new)")
    for v, kw in [("6", "decalogue"), ("12", "sabbath"), ("22", "sealed"), ("33", "walking")]:
        entry = existing.get("5", {}).get(v, "MISSING")
        print(f"  Deut 5:{v} — {'OK' if kw.lower() in entry.lower() else 'CHECK'}")
    for v, kw in [("4", "shema"), ("7", "teach"), ("9", "mezuzah"), ("20", "catechism")]:
        entry = existing.get("6", {}).get(v, "MISSING")
        print(f"  Deut 6:{v} — {'OK' if kw.lower() in entry.lower() else 'CHECK'}")
    for v, kw in [("2", "mesha"), ("6", "segulah"), ("7", "election"), ("13", "baal")]:
        entry = existing.get("7", {}).get(v, "MISSING")
        print(f"  Deut 7:{v} — {'OK' if kw.lower() in entry.lower() else 'CHECK'}")
    for ch in ["5", "6", "7"]:
        total = {"5": 33, "6": 25, "7": 26}[ch]
        present = len(existing.get(ch, {}))
        missing = [str(i) for i in range(1, total + 1) if str(i) not in existing.get(ch, {})]
        print(f"  Ch {ch}: {present}/{total} — missing: {missing if missing else 'none'}")


if __name__ == "__main__":
    main()
